/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportMonitoraDuplicatasDescontadas-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FilterFullText.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cliente:") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&FilterFullText) EndIf
If not (&CreVlrDup.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Valor:") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrDup EndIf
If not (&CreSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sts") If Not &CreSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreSts.EnumerationDescription() Endif EndIf
If not (&CreRecPag.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Receber") If Not &CreRecPag.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreRecPag.EnumerationDescription() Endif EndIf
If not (&CreVlrSdo.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Saldo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrSdo EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro1) EndIf Case &DynamicFiltersSelector1 = !'CREBLONRO' &CreBloNro1.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Bloqueto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreBloNro1) EndIf Case &DynamicFiltersSelector1 = !'CREDTAVCT' &CreDtaVct1.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaVct1.IsEmpty() OR not &CreDtaVct_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Vencimento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To1 EndIf Case &DynamicFiltersSelector1 = !'CREDTAEMS' &CreDtaEms1.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaEms1.IsEmpty() OR not &CreDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaEms_To1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro2) EndIf Case &DynamicFiltersSelector2 = !'CREBLONRO' &CreBloNro2.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Bloqueto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreBloNro2) EndIf Case &DynamicFiltersSelector2 = !'CREDTAVCT' &CreDtaVct2.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaVct2.IsEmpty() OR not &CreDtaVct_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Vencimento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To2 EndIf Case &DynamicFiltersSelector2 = !'CREDTAEMS' &CreDtaEms2.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaEms2.IsEmpty() OR not &CreDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaEms_To2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro3) EndIf Case &DynamicFiltersSelector3 = !'CREBLONRO' &CreBloNro3.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Bloqueto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreBloNro3) EndIf Case &DynamicFiltersSelector3 = !'CREDTAVCT' &CreDtaVct3.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaVct3.IsEmpty() OR not &CreDtaVct_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Vencimento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To3 EndIf Case &DynamicFiltersSelector3 = !'CREDTAEMS' &CreDtaEms3.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &CreDtaEms3.IsEmpty() OR not &CreDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaEms_To3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cód." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Dta Ems." &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Dta. Vct" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Abv" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Saldo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Bloqueto"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreSts CreRecPag CreDupNro when &OrderedBy = 1 order CreCod when &OrderedBy = 2 AND &OrderedDsc = False order (CreCod) when &OrderedBy = 2 AND &OrderedDsc = True order CreDupNro when &OrderedBy = 3 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 3 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 5 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 5 AND &OrderedDsc = True order CreAbvDup when &OrderedBy = 6 AND &OrderedDsc = False order (CreAbvDup) when &OrderedBy = 6 AND &OrderedDsc = True order CreVlrDup when &OrderedBy = 7 AND &OrderedDsc = False order (CreVlrDup) when &OrderedBy = 7 AND &OrderedDsc = True order CreVlrSdo when &OrderedBy = 8 AND &OrderedDsc = False order (CreVlrSdo) when &OrderedBy = 8 AND &OrderedDsc = True order CreBloNro when &OrderedBy = 9 AND &OrderedDsc = False order (CreBloNro) when &OrderedBy = 9 AND &OrderedDsc = True
using DSMonitoraDuplicatasDescontadas(&FilterFullText, &CreVlrDup, &CreSts, &CreRecPag, &CreVlrSdo, &DynamicFiltersSelector1 , &CreDupNro1, &CreBloNro1, &CreDtaVct1, &CreDtaVct_To1, &CreDtaEms1, &CreDtaEms_To1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &CreDupNro2, &CreBloNro2, &CreDtaVct2, &CreDtaVct_To2 , &CreDtaEms2, &CreDtaEms_To2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &CreDupNro3, &CreBloNro3 , &CreDtaVct3, &CreDtaVct_To3, &CreDtaEms3, &CreDtaEms_To3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CreCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(CreDupNro) if CreNovCliRaz_Formula.Length() > 30 &CreNovCliRaz = substr(CreNovCliRaz_Formula, 1, 30) + '...' Else &CreNovCliRaz = CreNovCliRaz_Formula EndIf &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&CreNovCliRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = CreDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = CreDtaVct &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = WWP_Export_SecureText(CreAbvDup) &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Number = CreVlrDup &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = CreVlrSdo &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(CreBloNro)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"MonitoraDuplicatasDescontadasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"MonitoraDuplicatasDescontadasGridState")) Else &GridState.FromXml(&Session.Get(!"MonitoraDuplicatasDescontadasGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILTERFULLTEXT" &FilterFullText.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRDUP" &CreVlrDup.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

